{
    uint16_t offsetIndex = 0U, offsetTrim = 0U;

    ASSERT(PGA_isBaseValid(base));

    //
    // Get the offset index for the PGA base
    //
    switch(base)
    {
        case PGA1_BASE:
            offsetIndex = (uint16_t)(0U);
            break;
        default:
            //
            // Invalid base address!
            //
            offsetIndex = (uint16_t)(0U);
            break;
    }

    if(TI_OTP_DEV_PRG_KEY == TI_OTP_DEV_KEY)
    {
        offsetTrim = (*(uint16_t *)(PGA_getOffsetTrimNOTPLoc(offsetIndex)));
        offsetTrim = (offsetTrim & PGA_OFFSETTRIM_PGA_OFFSETTRIMN_M);
    }
    else
    {
        offsetTrim = 0U;
    }

    //
    // Configure the offset trim, offset trim is not updated here in case of
    // untrimmed devices.
    //
    if(offsetTrim > 0x0U)
    {
        EALLOW;
        HWREG(base + PGA_O_OFFSETTRIM) |= offsetTrim;
        EDIS;
    }
}

{
    uint16_t offsetIndex = 0U;
    uint32_t offsetTrim = 0U;

    ASSERT(PGA_isBaseValid(base));

    //
    // Get the offset index for the PGA base
    //
    switch(base)
    {
        case PGA1_BASE:
            offsetIndex = (uint16_t)(0U);
            break;
        default:
            //
            // Invalid base address!
            //
            offsetIndex = (uint16_t)(0U);
            break;
    }

    if(TI_OTP_DEV_PRG_KEY == TI_OTP_DEV_KEY)
    {
        offsetTrim = (*(uint16_t *)(PGA_getOffsetTrimPOTPLoc(offsetIndex)));
        offsetTrim = (offsetTrim << PGA_OFFSETTRIM_PGA_OFFSETTRIMP_S);
    }
    else
    {
        offsetTrim = 0U;
    }

    //
    // Configure the offset trim, offset trim is not updated here in case of
    // untrimmed devices.
    //
    if(offsetTrim > 0x0U)
    {
        EALLOW;
        HWREG(base + PGA_O_OFFSETTRIM) |= offsetTrim;
        EDIS;
    }
}

{
    return(
           (base == PGA1_BASE)
          );
}

{
   ASSERT(PGA_isBaseValid(base));

   //
   // Set PGAEN bit
   //
   EALLOW;
   HWREG(base + PGA_O_CTL) |= (uint32_t)PGA_CTL_PGAEN;
   EDIS;
}

{
   ASSERT(PGA_isBaseValid(base));

   //
   // Clear PGAEN bit
   //
   EALLOW;
   HWREG(base + PGA_O_CTL) &= ~((uint32_t)PGA_CTL_PGAEN);
   EDIS;
}

{
    ASSERT(PGA_isBaseValid(base));

    //
    // Write to the GAIN bits
    //
    EALLOW;
    HWREG(base + PGA_O_CTL) = ((HWREG(base + PGA_O_CTL) &
                                ~((uint32_t)PGA_CTL_GAIN_M)) |
                               (uint16_t)gainValue);
    EDIS;
}

{
    ASSERT(PGA_isBaseValid(base));

    //
    // Write to the FILTRESSEL bits
    //
    EALLOW;
    HWREGH(base + PGA_O_CTL) =
                          ((HWREGH(base + PGA_O_CTL) &
                            ~((uint16_t)PGA_CTL_FILT_RES_SEL_M)) |
                           (uint16_t)resistorValue);
    EDIS;
}

{

    EALLOW;
    HWREGH(base + PGA_O_CTL) |= (uint16_t)PGA_CTL_PGA_OUTENABLE;
    EDIS;

}

{
    ASSERT(PGA_isBaseValid(base));

    EALLOW;
    HWREGH(base + PGA_O_CTL) &= ~((uint16_t)PGA_CTL_PGA_OUTENABLE);
    EDIS;

}

{
    ASSERT(PGA_isBaseValid(base));

    EALLOW;
    HWREGH(base + PGA_O_CTL) |= (uint16_t)PGA_CTL_PGA_OUTEN_INTGAIN;
    EDIS;

}

{
    ASSERT(PGA_isBaseValid(base));

    EALLOW;
    HWREGH(base + PGA_O_CTL) &= ~((uint16_t)PGA_CTL_PGA_OUTEN_INTGAIN);
    EDIS;

}

{
